SELECT DISTINCT model_id, model_name 
FROM models 
WHERE last_updated_date > '2022-02-01';

SELECT *
FROM model_evaluation_history
WHERE model_id = 1;

SELECT model_id, model_name
FROM models
WHERE model_id NOT IN (SELECT model_id FROM user_models);

SELECT COUNT(DISTINCT model_id) AS num_models_evaluated_recently
FROM model_evaluation_history
WHERE evaluation_date >= date('now', '-30 days');
